// GetIconPaths returns the inner SVG markup for the given icon name.
// Returns a fallback question-mark icon if the name is not found.
func GetIconPaths(name string) string {
	if p, ok := iconPaths[name]; ok {
		return p
	}
	return `<circle cx="12" cy="12" r="10"/><path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"/><path d="M12 17h.01"/>`
}
